const dailyLogs = $items("Execute a SQL query").map(i => i.json);
const meals = $items("Execute a SQL query1").map(i => i.json);
const dailyTotals = $items("Execute a SQL query2").map(i => i.json);

// ---- Daily log map ----
const logMap = {};
dailyLogs.forEach(d => {
  logMap[d.daily_log_id] = {
    date: d.log_date,
    weight: d.morning_weight_kg,
    meals: [],
    totals: {
      calories: 0,
      protein: 0,
      carbs: 0,
      fat: 0,
    },
  };
});

// ---- Attach meals ----
meals.forEach(m => {
  const log = logMap[m.daily_log_id];
  if (!log) return;

  log.meals.push({
    meal_type: m.meal_type,
    food_name: m.food_name,
    grams: m.grams,
    calories: m.calories,
    protein: m.protein_g,
    carbs: m.carbs_g,
    fat: m.fat_g,
  });

  log.totals.calories += m.calories;
  log.totals.protein += m.protein_g;
  log.totals.carbs += m.carbs_g;
  log.totals.fat += m.fat_g;
});

// ---- Chart-ready arrays ----
const chartCalories = dailyTotals.map(d => ({
  date: d.log_date,
  calories: d.total_calories,
}));

const chartMacros = dailyTotals.map(d => ({
  date: d.log_date,
  protein: d.total_protein,
  carbs: d.total_carbs,
  fat: d.total_fat,
}));

return [
  {
    json: {
      status: "ok",
      charts: {
        calories_over_time: chartCalories,
        macros_over_time: chartMacros,
      },
      daily_logs: Object.values(logMap),
    },
  },
];
